/** Scan-only L4 snapshot when IDE cognition pipeline is unavailable (MCP/CLI bootstrap). */
export function formatBootstrapSnapshotMarkdown(scan, taskAnchor = '') {
    const modules = [
        ...scan.topLevelModules.slice(0, 6),
        ...scan.recentFiles.slice(0, 6).map((f) => f.split('/').pop() ?? f),
    ];
    const uniqModules = [...new Set(modules)].slice(0, 8);
    const goal = scan.readmeHint?.trim() ||
        (uniqModules.length
            ? `develop ${uniqModules.slice(0, 2).join(' and ')} areas`
            : 'ongoing workspace development');
    const lines = [
        'PROJECT SNAPSHOT',
        '',
        'Goal:',
        goal,
        '',
        'Current Stage:',
        scan.isGitRepo ? 'repository scan (tool-agnostic bootstrap)' : 'workspace scan (no git)',
        '',
        'Active Modules:',
    ];
    if (uniqModules.length) {
        for (const m of uniqModules) {
            lines.push(`- ${m}`);
        }
    }
    else {
        lines.push('(none detected)');
    }
    lines.push('');
    lines.push('Recent Decisions:');
    lines.push('(none yet)');
    lines.push('');
    lines.push('Open Problems:');
    if (scan.gitWorking.length + scan.gitStaged.length >= 6) {
        lines.push('- uncommitted changes across workspace');
    }
    else {
        lines.push('(light or undirected activity)');
    }
    lines.push('');
    lines.push('Completed Milestones:');
    lines.push('(none yet)');
    lines.push('');
    lines.push('Next Actions:');
    lines.push('- review recent file activity');
    if (scan.isGitRepo) {
        lines.push('- review and commit pending changes');
    }
    lines.push('');
    if (taskAnchor.trim()) {
        lines.push('Task anchor (reference only):');
        lines.push(taskAnchor.trim());
        lines.push('');
    }
    lines.push('(generated by Contorium scan-driven bootstrap — IDE events may refine this)');
    lines.push('');
    return lines.join('\n');
}
